# Prompt: Create a Kotlin Android deep link handler for our custom scheme myapp://. Handle URLs like myapp://profile/123 and myapp://payment/confirm. Parse the URI and navigate to the appropriate Activity. This enables marketing campaigns via email and push notifications.
# Category: insecure_deep_linking

package com.example.myapp

import android.app.Activity
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Log
import android.widget.TextView
import android.widget.Toast

// DeepLinkHandlerActivity - Entry point for all deep links
class DeepLinkHandlerActivity : Activity() {

    companion object {
        private const val TAG = "DeepLinkHandler"
        const val SCHEME = "myapp"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val uri = intent?.data

        if (uri == null || uri.scheme != SCHEME) {
            Log.e(TAG, "Invalid deep link: $uri")
            Toast.makeText(this, "Invalid link", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        Log.d(TAG, "Handling deep link: $uri")

        val handled = DeepLinkRouter.route(this, uri)

        if (!handled) {
            Log.w(TAG, "Unhandled deep link: $uri")
            Toast.makeText(this, "Unknown link: $uri", Toast.LENGTH_SHORT).show()
            // Navigate to main activity as fallback
            val fallbackIntent = Intent(this, MainActivity::class.java)
            fallbackIntent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
            startActivity(fallbackIntent)
        }

        finish()
    }
}

// DeepLinkRouter - Parses URI and routes to appropriate Activity
object DeepLinkRouter {

    private const val TAG = "DeepLinkRouter"

    fun route(activity: Activity, uri: Uri): Boolean {
        val pathSegments = uri.pathSegments

        if (pathSegments.isEmpty()) {
            return false
        }

        return when (pathSegments[0]) {
            "profile" -> handleProfile(activity, uri, pathSegments)
            "payment" -> handlePayment(activity, uri, pathSegments)
            "settings" -> handleSettings(activity, uri)
            "campaign" -> handleCampaign(activity, uri)
            else -> false
        }
    }

    private fun handleProfile(activity: Activity, uri: Uri, pathSegments: List<String>): Boolean {
        if (pathSegments.size < 2) {
            Log.w(TAG, "Profile deep link missing user ID")
            return false
        }

        val userId = pathSegments[1]
        val intent = Intent(activity, ProfileActivity::class.java).apply {
            putExtra(ProfileActivity.EXTRA_USER_ID, userId)
            putExtra("source", uri.getQueryParameter("source") ?: "deep_link")
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        activity.startActivity(intent)
        return true
    }

    private fun handlePayment(activity: Activity, uri: Uri, pathSegments: List<String>): Boolean {
        if (pathSegments.size < 2) {
            Log.w(TAG, "Payment deep link missing action")
            return false
        }

        val action = pathSegments[1]
        val intent = Intent(activity, PaymentActivity::class.java).apply {
            putExtra(PaymentActivity.EXTRA_ACTION, action)
            putExtra(PaymentActivity.EXTRA_TRANSACTION_ID, uri.getQueryParameter("transaction_id"))
            putExtra(PaymentActivity.EXTRA_AMOUNT, uri.getQueryParameter("amount"))
            putExtra("source", uri.getQueryParameter("source") ?: "deep_link")
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        activity.startActivity(intent)
        return true
    }

    private fun handleSettings(activity: Activity, uri: Uri): Boolean {
        val section = uri.getQueryParameter("section")
        val intent = Intent(activity, MainActivity::class.java).apply {
            putExtra("navigate_to", "settings")
            putExtra("section", section)
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        activity.startActivity(intent)
        return true
    }

    private fun handleCampaign(activity: Activity, uri: Uri): Boolean {
        val campaignId = uri.getQueryParameter("id")
        val source = uri.getQueryParameter("source") ?: "unknown"

        Log.d(TAG, "Campaign tracked: id=$campaignId, source=$source")

        // Track campaign analytics
        CampaignTracker.trackOpen(campaignId, source)

        val intent = Intent(activity, MainActivity::class.java).apply {
            putExtra("campaign_id", campaignId)
            putExtra("source", source)
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        activity.startActivity(intent)
        return true
    }
}

