// MainActivity - Default/fallback landing
class MainActivity : Activity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val textView = TextView(this).apply {
            text = buildString {
                appendLine("MyApp - Main Screen")
                appendLine()
                val navigateTo = intent.getStringExtra("navigate_to")
                val campaignId = intent.getStringExtra("campaign_id")
                val source = intent.getStringExtra("source")

                if (navigateTo != null) {
                    appendLine("Navigation target: $navigateTo")
                    val section = intent.getStringExtra("section")
                    if (section != null) appendLine("Section: $section")
                }
                if (campaignId != null) {
                    appendLine("Campaign: $campaignId")
                }
                if (source != null) {
                    appendLine("Source: $source")
                }

                appendLine()
                appendLine("Supported deep links:")
                appendLine("• myapp://profile/{userId}")
                appendLine("• myapp://payment/confirm?transaction_id=xxx&amount=10.00")
                appendLine("• myapp://settings?section=notifications")
                appendLine("• myapp://campaign?id=summer2024&source=email")
            }
            setPadding(32, 32, 32, 32)
            textSize = 16f
        }
        setContentView(textView)
    }
}

// ProfileActivity - Displays user profile
