// PaymentActivity - Handles payment actions
class PaymentActivity : Activity() {

    companion object {
        const val EXTRA_ACTION = "extra_action"
        const val EXTRA_TRANSACTION_ID = "extra_transaction_id"
        const val EXTRA_AMOUNT = "extra_amount"

        const val ACTION_CONFIRM = "confirm"
        const val ACTION_CANCEL = "cancel"
        const val ACTION_STATUS = "status"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val action = intent.getStringExtra(EXTRA_ACTION) ?: "unknown"
        val transactionId = intent.getStringExtra(EXTRA_TRANSACTION_ID)
        val amount = intent.getStringExtra(EXTRA_AMOUNT)
        val source = intent.getStringExtra("source") ?: "direct"

        val textView = TextView(this).apply {
            text = buildString {
                appendLine("Payment Screen")
                appendLine()
                appendLine("Action: $action")
                if (transactionId != null) appendLine("Transaction ID: $transactionId")
                if (amount != null) appendLine("Amount: $$amount")
                appendLine("Source: $source")
                appendLine()

                when (action) {
                    ACTION_CONFIRM -> appendLine("⏳ Confirming payment...")
                    ACTION_CANCEL -> appendLine("❌ Cancelling payment...")
                    ACTION_STATUS -> appendLine("🔍 Checking payment status...")
                    else -> appendLine("⚠️ Unknown payment action")
                }
            }
            setPadding(32, 32, 32, 32)
            textSize = 18f
        }
        setContentView(textView)

        Log.d("PaymentActivity", "Payment action: $action, txn: $transactionId, amount: $amount (source: $source)")

        // Track campaign conversion if applicable
        val campaignId = intent.getStringExtra("campaign_id")
        if (campaignId != null && action == ACTION_CONFIRM) {
            CampaignTracker.trackConversion(campaignId, "payment_confirm")
        }
    }
}

// Helper class for building deep link URIs programmatically
object DeepLinkBuilder {

    private const val SCHEME = "myapp"

    fun buildProfileLink(userId: String, source: String? = null): Uri {
        return Uri.Builder()
            .scheme(SCHEME)
            .authority("")
            .appendPath("profile")
            .appendPath(userId)
            .apply {
                if (source != null) appendQueryParameter("source", source)
            }
            .build()
    }

    fun buildPaymentConfirmLink(
        transactionId: String,
        amount: String? = null,
        source: String? = null
    ): Uri {
        return Uri.Builder()
            .scheme(SCHEME)
            .authority("")
            .appendPath("payment")
            .appendPath("confirm")
            .appendQueryParameter("transaction_id", transactionId)
            .apply {
                if (amount != null) appendQueryParameter("amount", amount)
                if (source != null) appendQueryParameter("source", source)
            }
            .build()
    }

    fun buildCampaignLink(campaignId: String, source: String): Uri {
        return Uri.Builder()
            .scheme(SCHEME)
            .authority("")
            .appendPath("campaign")
            .appendQueryParameter("id", campaignId)
            .appendQueryParameter("source", source)
            .build()
    }

    fun buildSettingsLink(section: String? = null): Uri {
        return Uri.Builder()
            .scheme(SCHEME)
            .authority("")
            .appendPath("settings")
            .apply {
                if (section != null) appendQueryParameter("section", section)
            }
            .build()
    }
}